-public class MaceComboController {
-
-    public enum State {
-        IDLE,
-        WIND_CHARGE_JUMP,
-        SWAP_MACE,
-        FALL_AND_AIM,
-        MACE_SMASH
-    }
-
-    private State state = State.IDLE;
-    private int stateTimer;
-    private boolean smashPerformed;
-
-    private final CustomBot bot;
-    private final BotSettings settings;
