package com.pvpbot.npc;

import com.pvpbot.PvPBotPlugin;
import com.pvpbot.bot.BotSettings;
import net.citizensnpcs.api.trait.Trait;
import net.minecraft.server.level.ServerPlayer;
import org.bukkit.craftbukkit.entity.CraftPlayer;
import org.bukkit.entity.Player;

public class PvPBotTrait extends Trait {

    private BotSettings settings;
    private int tickCounter = 0;

    public PvPBotTrait() {
        super("pvpbot");
    }

    @Override
    public void onAttach() {
        this.settings = new BotSettings();
        this.settings.loadFromConfig(PvPBotPlugin.getInstance().getConfig());
    }

    @Override
    public void run() {
        if (!npc.isSpawned()) return;

        try {
            Player player = (Player) npc.getEntity();
            if (player == null) return;

            ServerPlayer nmsPlayer = ((CraftPlayer) player).getHandle();
            tickCounter++;

            if (tickCounter % 100 == 0) {
                PvPBotPlugin.getInstance().getLogger().info(
                    "PvPBot Trait ticking for " + npc.getName()
                );
            }
        } catch (Exception e) {
            PvPBotPlugin.getInstance().getLogger().warning(
                "Error in PvPBotTrait tick: " + e.getMessage()
            );
        }
    }

    public BotSettings getSettings() {
        return settings;
    }

    public void setSettings(BotSettings settings) {
        this.settings = settings;
    }
}

package com.pvpbot.bot;

import com.pvpbot.PvPBotPlugin;
import com.pvpbot.npc.PvPBotTrait;
import net.citizensnpcs.api.CitizensAPI;
import net.citizensnpcs.api.npc.NPC;
import net.citizensnpcs.api.npc.NPCRegistry;
import org.bukkit.Location;
import org.bukkit.entity.EntityType;
import org.bukkit.plugin.Plugin;

import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;

public class BotManager {

    private final Map<UUID, NPC> activeNPCs = new ConcurrentHashMap<>();
    private final Plugin plugin;

    public BotManager(Plugin plugin) {
        this.plugin = plugin;
    }

    public NPC spawnBot(Location loc, String name) {
        NPCRegistry registry = CitizensAPI.getNPCRegistry();
        NPC npc = registry.createNPC(EntityType.PLAYER, name);
        npc.addTrait(PvPBotTrait.class);

        PvPBotTrait trait = npc.getTraitNullable(PvPBotTrait.class);
        if (trait != null) {
            BotSettings defaults = new BotSettings();
            defaults.loadFromConfig(plugin.getConfig());
            trait.setSettings(defaults);
            npc.data().set(NPC.NAMEPLATE_VISIBLE_METADATA, defaults.isShowInTab());
        }

        npc.spawn(loc);

        if (trait != null && !trait.getSettings().isShowInTab()) {
            plugin.getServer().getScheduler().runTaskLater(plugin, () -> {
                if (npc.isSpawned()) {
                    npc.data().set(NPC.NAMEPLATE_VISIBLE_METADATA, false);
                }
            }, 40L);
        }

        activeNPCs.put(npc.getUniqueId(), npc);
        plugin.getLogger().info("Spawned bot: " + name + " at " + loc.getWorld().getName() + " " +
                loc.getBlockX() + " " + loc.getBlockY() + " " + loc.getBlockZ());
        return npc;
    }

    public void removeBot(String name) {
        for (Map.Entry<UUID, NPC> entry : activeNPCs.entrySet()) {
            NPC npc = entry.getValue();
            if (npc.getName().equals(name)) {
                npc.destroy();
                activeNPCs.remove(entry.getKey());
                plugin.getLogger().info("Removed bot: " + name);
                return;
            }
        }
        plugin.getLogger().warning("Bot not found: " + name);
    }

    public void removeAll() {
        for (NPC npc : activeNPCs.values()) {
            npc.destroy();
        }
        activeNPCs.clear();
        plugin.getLogger().info("All bots removed.");
    }

    public NPC getNPC(String name) {
        for (NPC npc : activeNPCs.values()) {
            if (npc.getName().equals(name)) {
                return npc;
            }
        }
        return null;
    }

    public Map<UUID, NPC> getActiveNPCs() {
        return activeNPCs;
    }
}

package com.pvpbot;

import com.pvpbot.bot.BotManager;
import com.pvpbot.command.PvPBotCommand;
import org.bukkit.plugin.java.JavaPlugin;

public class PvPBotPlugin extends JavaPlugin {

    private BotManager botManager;
    private static PvPBotPlugin instance;

    @Override
    public void onEnable() {
        instance = this;
        saveDefaultConfig();
        botManager = new BotManager(this);

        PvPBotCommand commandExecutor = new PvPBotCommand(botManager);
        getCommand("pvpbot").setExecutor(commandExecutor);
        getCommand("pvpbot").setTabCompleter(commandExecutor);

        getLogger().info("PvPBot v" + getDescription().getVersion() + " enabled successfully.");
    }

    @Override
    public void onDisable() {
        if (botManager != null) {
            botManager.removeAll();
        }
        getLogger().info("PvPBot disabled.");
    }

    public static PvPBotPlugin getInstance() {
        return instance;
    }

    public BotManager getBotManager() {
        return botManager;
    }
}

package com.pvpbot.command;

import com.pvpbot.bot.BotManager;
import org.bukkit.ChatColor;
import org.bukkit.command.Command;
import org.bukkit.command.CommandSender;
import org.bukkit.command.TabExecutor;
import org.bukkit.entity.Player;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class PvPBotCommand implements TabExecutor {

    private final BotManager botManager;

    private static final List<String> SUBCOMMANDS = Arrays.asList("spawn", "remove", "removeall");

    public PvPBotCommand(BotManager botManager) {
        this.botManager = botManager;
    }

    @Override
    public boolean onCommand(CommandSender sender, Command command, String label, String[] args) {
        if (args.length == 0) {
            sender.sendMessage(ChatColor.RED + "Usage: /pvpbot <spawn|remove|removeall> [name]");
            return true;
        }

        switch (args[0].toLowerCase()) {
            case "spawn":
                return handleSpawn(sender, args);
            case "remove":
                return handleRemove(sender, args);
            case "removeall":
                return handleRemoveAll(sender);
            default:
                sender.sendMessage(ChatColor.RED + "Unknown subcommand. Use: spawn, remove, removeall");
                return true;
        }
    }

    private boolean handleSpawn(CommandSender sender, String[] args) {
        if (!(sender instanceof Player player)) {
            sender.sendMessage(ChatColor.RED + "Only players can spawn bots.");
            return true;
        }

        String name = args.length >= 2 ? args[1] : "PvPBot";
        botManager.spawnBot(player.getLocation(), name);
        sender.sendMessage(ChatColor.GREEN + "Spawned bot: " + name);
        return true;
    }

    private boolean handleRemove(CommandSender sender, String[] args) {
        if (args.length < 2) {
            sender.sendMessage(ChatColor.RED + "Usage: /pvpbot remove <name>");
            return true;
        }

        String name = args[1];
        botManager.removeBot(name);
        sender.sendMessage(ChatColor.GREEN + "Removed bot: " + name);
        return true;
    }

    private boolean handleRemoveAll(CommandSender sender) {
        botManager.removeAll();
        sender.sendMessage(ChatColor.GREEN + "All bots removed.");
        return true;
    }

    @Override
    public List<String> onTabComplete(CommandSender sender, Command command, String alias, String[] args) {
        if (args.length == 1) {
            String partial = args[0].toLowerCase();
            List<String> result = new ArrayList<>();
            for (String sub : SUBCOMMANDS) {
                if (sub.startsWith(partial)) {
                    result.add(sub);
                }
            }
            return result;
        }

        if (args.length == 2 && args[0].equalsIgnoreCase("remove")) {
            String partial = args[1].toLowerCase();
            List<String> result = new ArrayList<>();
            for (String name : botManager.getActiveNPCs().values().stream()
                    .map(npc -> npc.getName()).toList()) {
                if (name.toLowerCase().startsWith(partial)) {
                    result.add(name);
                }
            }
            return result;
        }

        return List.of();
    }
}

