         Inventory inv = Bukkit.createInventory(null, 54, TITLES.get(page));
         Material borderMat = BORDER_COLORS.getOrDefault(page, Material.GRAY_STAINED_GLASS_PANE);
         ItemStack border = createItem(borderMat, " ");
         for (int i = 0; i < 54; i++) {
