         List<String> lore = new ArrayList<>();
         if (type == BotSettings.SettingType.BOOLEAN) {
             boolean boolVal = value instanceof Boolean && (Boolean) value;
             Material mat = boolVal ? Material.LIME_WOOL : Material.RED_WOOL;
