+        instance.getLogger().info("[DEBUG] " + message);
+        for (Player player : instance.getServer().getOnlinePlayers()) {
+            if (player.hasPermission("pvpbot.admin")) {
+                player.sendMessage(ChatColor.GRAY + "[PvPDebug] " + ChatColor.WHITE + message);
+            }
+        }
+    }
 }

