     private boolean handleSettings(CommandSender sender, String[] args) {
         if (args.length == 1) {
             sender.sendMessage(ChatColor.GOLD + "=== Global Bot Settings ===");
             for (String key : BotSettings.SETTING_KEYS) {
                 Object val = defaultSettings.getValue(key);
